def factorial(n):
    resultado = 1
    for i in range(2, n + 1):
        resultado *= i
    return resultado

print(f'5! = {factorial(5)}')

def factorial(n):
    if n <= 1:
        return 1
    return n * factorial(n - 1)

print(f'6! = {factorial(6)}')

def fibonacci(n):
    if n == 0:
        return 0
    if n == 1:
        return 1
    return fibonacci(n - 1) + fibonacci(n - 2)

for i in range(8):
    print(fibonacci(i), end=' ')
