def cifrado_cesar(texto, desplazamiento=3):
    resultado = ''
    for caracter in texto:
        if caracter.isupper():
            resultado += chr((ord(caracter) - ord('A') + desplazamiento) % 26 + ord('A'))
        elif caracter.islower():
            resultado += chr((ord(caracter) - ord('a') + desplazamiento) % 26 + ord('a'))
        else:
            resultado += caracter
    return resultado

texto = 'Hola Mundo'
cifrado = cifrado_cesar(texto)
print(f'Original: {texto}')
print(f'Cifrado:  {cifrado}')

